const body = $input.first().json.body || {};
const intent     = (body.intent || '').toLowerCase();
const plan       = body.plan       || null;
const paymentType = (body.paymentType || 'monthly').toLowerCase();
const buyer      = body.buyer      || {};

const buyerName     = (buyer.name     || '').trim();
const buyerLastName = (buyer.lastName || '').trim();
const buyerEmail    = (buyer.email    || '').toLowerCase().trim();

if (!buyerEmail) throw new Error('Email del comprador es requerido');
if (!plan)       throw new Error('Plan es requerido');

// custom_value3 en Invoice Ninja == slug del plan
const planFamily = plan;

// Planes '-ven' requieren cuota inicial (Unico) + primer mes + recurrente mensual
const isVen = planFamily.endsWith('-ven');

// Mapear paymentType al custom_value2 de Invoice Ninja
const frequencyLabel = paymentType === 'annual' ? 'Annualy' : 'Monthly';

// frequency_id de Invoice Ninja: 4 = mensual, 9 = anual
const frequencyId = paymentType === 'annual' ? 9 : 4;

return [{ json: {
  intent,
  plan,
  planFamily,
  paymentType,
  isVen,
  frequencyLabel,
  frequencyId,
  buyer: {
    name:      buyerName,
    lastName:  buyerLastName,
    email:     buyerEmail,
    phone:     buyer.phone     || '',
    cedula:    buyer.cedula    || '',
    birthDate: buyer.birthDate || '',
    zip:       buyer.zip       || '',
  },
  family:         body.family    || [],
  timestamp:      body.timestamp || new Date().toISOString(),
  customerEmail:  buyerEmail,
  customerName:   (buyerName + ' ' + buyerLastName).trim(),
  firstName:      buyerName,
  lastName:       buyerLastName,
  customerPhone:  buyer.phone   || '',
  customerCedula: buyer.cedula  || '',
} }];

const inResponse = $input.first().json;
const ctx        = $('Parse & Validate Request').item.json;

const clientsArr = (inResponse.data && Array.isArray(inResponse.data))
  ? inResponse.data : [];

const existing = clientsArr.find(c => {
  const contacts = c.contacts || [];
  return contacts.some(ct =>
    ct.email && ct.email.toLowerCase().trim() === ctx.customerEmail
  );
});

if (existing) {
  return [{ json: { ...ctx, clientId: existing.id, isNewClient: false } }];
} else {
  return [{ json: { ...ctx, clientId: null,        isNewClient: true  } }];
}

// Convergencia: viene de 'Create Client' (nuevo) o de 'Is New Client?' false (existente)
const inputJson = $input.first().json;
let clientId, ctx;

// Caso A: respuesta de Invoice Ninja al crear cliente
if (inputJson.data && inputJson.data.id) {
  clientId = inputJson.data.id;
  ctx      = $('Evaluate Client Exists').item.json;
}
// Caso A alternativo: IN devuelve objeto directo sin wrapper .data
else if (inputJson.id && !inputJson.planFamily) {
  clientId = inputJson.id;
  ctx      = $('Evaluate Client Exists').item.json;
}
// Caso B: cliente existente — ya tiene clientId en el json
else if (inputJson.clientId) {
  clientId = inputJson.clientId;
  ctx      = inputJson;
}
else {
  throw new Error('No se pudo resolver clientId. Input: ' + JSON.stringify(inputJson));
}

if (!clientId) throw new Error('clientId es null o undefined');
return [{ json: { ...ctx, clientId } }];

// Consulta productos de Invoice Ninja y determina la estrategia de facturación
const ctx = $input.first().json;

const BASE    = 'https://invoicing.legadoholding.com/api/v1';
const TOKEN   = 'WXngbLQXx5RPDsH0APTEopqf4Ja9U6Jdyt8MQK5qoVicK6jfNUCXDqDy5mXprtTV';
const HEADERS = { 'X-API-TOKEN': TOKEN, 'Accept': 'application/json' };

// Obtener catálogo de productos
const resp = await $helpers.httpRequest({
  method: 'GET',
  url: BASE + '/products?per_page=100',
  headers: HEADERS,
});
const data = typeof resp === 'string' ? JSON.parse(resp) : resp;
const allProducts = (data.data || []).filter(p => !p.is_deleted && p.custom_value1 === 'legadoweb');

// Filtrar por familia del plan (custom_value3 == planFamily)
const familyProducts = allProducts.filter(p => p.custom_value3 === ctx.planFamily);

if (familyProducts.length === 0) {
  throw new Error(`Sin productos para la familia '${ctx.planFamily}'. Verifica custom_value3 en Invoice Ninja.`);
}

let strategy, lineItems1, lineItems2, frequencyId2;

if (ctx.isVen) {
  // Planes Venezuela: buscar producto Unico (cuota inicial) y Monthly (mensualidad)
  const unicoProd   = familyProducts.find(p => (p.custom_value2 || '').toLowerCase() === 'unico');
  const monthlyProd = familyProducts.find(p => (p.custom_value2 || '').toLowerCase() === 'monthly');

  if (!unicoProd)   throw new Error(`Producto 'Unico' no encontrado para '${ctx.planFamily}'`);
  if (!monthlyProd) throw new Error(`Producto 'Monthly' no encontrado para '${ctx.planFamily}'`);

  strategy = 'ven';

  // Factura única: cuota inicial + primer mes
  lineItems1 = [
    { product_key: unicoProd.product_key,   notes: unicoProd.notes   || 'Cuota inicial del plan',   cost: unicoProd.price,   qty: 1 },
    { product_key: monthlyProd.product_key, notes: 'Primer mes de mensualidad',                      cost: monthlyProd.price, qty: 1 },
  ];

  // Factura recurrente mensual (mensualidades siguientes)
  lineItems2   = [{ product_key: monthlyProd.product_key, notes: monthlyProd.notes || 'Mensualidad del plan', cost: monthlyProd.price, qty: 1 }];
  frequencyId2 = 4; // mensual

} else {
  // Planes Zulia: buscar producto que coincida con la frecuencia seleccionada
  const targetProd = familyProducts.find(p =>
    (p.custom_value2 || '').toLowerCase() === ctx.frequencyLabel.toLowerCase()
  );

  if (!targetProd) {
    throw new Error(`Producto no encontrado para familia '${ctx.planFamily}' con frecuencia '${ctx.frequencyLabel}'`);
  }

  strategy     = ctx.paymentType === 'annual' ? 'zulia-annual' : 'zulia-monthly';
  lineItems1   = [{ product_key: targetProd.product_key, notes: targetProd.notes || '', cost: targetProd.price, qty: 1 }];
  lineItems2   = null;
  frequencyId2 = null;
}

return [{ json: { ...ctx, strategy, lineItems1, lineItems2, frequencyId2 } }];

// Crea la factura de primer pago (siempre una factura regular para obtener enlace de pago)
// y una factura recurrente para los pagos futuros.
const ctx = $input.first().json;

const BASE    = 'https://invoicing.legadoholding.com/api/v1';
const TOKEN   = 'WXngbLQXx5RPDsH0APTEopqf4Ja9U6Jdyt8MQK5qoVicK6jfNUCXDqDy5mXprtTV';
const HEADERS = { 'X-API-TOKEN': TOKEN, 'Content-Type': 'application/json', 'Accept': 'application/json' };

const post = async (path, body) => {
  const r = await $helpers.httpRequest({
    method:  'POST',
    url:     BASE + path,
    headers: HEADERS,
    body:    JSON.stringify(body),
  });
  return typeof r === 'string' ? JSON.parse(r) : r;
};

const toLineItems = (items) => items.map(li => ({
  product_key: li.product_key,
  notes:       li.notes    || '',
  cost:        li.cost,
  quantity:    li.qty      || 1,
}));

// ── Calcular total del primer pago ────────────────────────────────────────────
const invoiceTotal = ctx.lineItems1
  .reduce((sum, li) => sum + (li.cost * (li.qty || 1)), 0)
  .toFixed(2);

// ── 1. Factura regular para el PRIMER pago (tiene enlace de pago) ────────────
const firstResp    = await post('/invoices', {
  client_id:  ctx.clientId,
  line_items: toLineItems(ctx.lineItems1),
});
const firstInvoice = firstResp.data || firstResp;
const invLink      = (firstInvoice.invitations && firstInvoice.invitations[0])
  ? firstInvoice.invitations[0].link
  : '';

// ── 2. Factura recurrente para pagos futuros ─────────────────────────────────
const recurringFreqId = ctx.strategy === 'ven' ? ctx.frequencyId2 : ctx.frequencyId;
const recurringItems  = ctx.strategy === 'ven' ? ctx.lineItems2   : ctx.lineItems1;

// Para planes ven, la recurrente empieza el mes siguiente
let nextSendDate = undefined;
if (ctx.strategy === 'ven') {
  const now  = new Date();
  const next = new Date(now.getFullYear(), now.getMonth() + 1, 1);
  nextSendDate = next.toISOString().split('T')[0];
}

const recurringBody = {
  client_id:    ctx.clientId,
  frequency_id: recurringFreqId,
  status_id:    2,       // activo
  auto_bill:    'off',   // el cliente paga manualmente vía enlace
  line_items:   toLineItems(recurringItems),
};
if (nextSendDate) recurringBody.next_send_date = nextSendDate;

await post('/recurring_invoices', recurringBody);

// ── Descripción legible de la estrategia (para el email) ─────────────────────
const strategyLabel = {
  'zulia-monthly': 'Suscripción mensual',
  'zulia-annual':  'Suscripción anual',
  'ven':           'Pago inicial + primer mes',
}[ctx.strategy] || ctx.strategy;

return [{ json: {
  ...ctx,
  invoiceId:      firstInvoice.id     || '',
  invoiceNumber:  firstInvoice.number || '',
  invitationLink: invLink,
  invoiceTotal,
  strategyLabel,
} }];
